INSERT INTO team_messages (campanha_id, sender_id, titulo, conteudo, prioridade, target_roles, target_cidade, cidade) VALUES
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', '32f18f2e-37ad-4a29-8c02-239f37126514', 'Reunião de alinhamento - Salvador', 'Prezados, confirmar presença na reunião de amanhã às 14h no comitê central de Salvador. Pauta: resultados da semana e planejamento de ações.', 'alta', '{}', null, 'Salvador'),
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', '32f18f2e-37ad-4a29-8c02-239f37126514', 'Meta de apoiadores - Março', 'Equipe, precisamos intensificar o cadastro de apoiadores. Meta: 500 novos cadastros até o fim do mês. Foco nas regiões de Feira de Santana e Itabuna.', 'normal', '{}', null, null),
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', '3924f6df-0d5c-4160-b09a-7117e579a963', 'Relatório de campo - Feira de Santana', 'Boa receptividade no bairro Tomba. Identificamos 3 novas lideranças locais. Material distribuído: 200 panfletos e 50 adesivos.', 'normal', '{}', null, 'Feira de Santana'),
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', '32f18f2e-37ad-4a29-8c02-239f37126514', 'URGENTE: Mudança de agenda', 'O comício previsto para sábado em Vitória da Conquista foi antecipado para sexta-feira às 18h. Favor repassar a todos os coordenadores municipais.', 'urgente', '{"admin","coordinator"}', null, null),
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', 'c992c29f-1003-45e8-8846-5332c5b70abe', 'Demanda identificada - Juazeiro', 'Durante visita ao bairro Alto do Cruzeiro, moradores relataram problemas graves com abastecimento de água. Sugerir pauta para o candidato.', 'alta', '{}', null, 'Juazeiro'),
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', '32f18f2e-37ad-4a29-8c02-239f37126514', 'Novos materiais disponíveis', 'Santinhos e banners atualizados já disponíveis para retirada no comitê central. Coordenadores municipais devem solicitar quantidade via módulo de Recursos.', 'normal', '{}', null, null),
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', '4fcb8699-1c8b-4f42-9531-44b10401bcd8', 'Feedback positivo - Barreiras', 'Excelente recepção no centro de Barreiras. Empresários locais demonstraram apoio. Agendamos reunião com associação comercial para próxima semana.', 'normal', '{}', null, 'Barreiras'),
('277894b4-d06c-4e96-a4a1-53f45d4f97a9', '32f18f2e-37ad-4a29-8c02-239f37126514', 'Treinamento de equipe', 'Lembrete: treinamento obrigatório para todos os usuários do sistema nesta quarta-feira às 10h. Link da videoconferência será enviado por WhatsApp.', 'alta', '{"user"}', null, null);
